const body = $input.first().json.body || $input.first().json;

const chatId = body.chat_id;
const adminName = body.admin_name || 'Admin';
const teamName = body.team_name || 'Unknown Team';
const subteamName = body.subteam_name || 'Unknown Subteam';
const senderName = body.sender_name || 'A team member';
const reportMarkdown = body.report_markdown || '';

if (!chatId) throw new Error('chat_id is missing');
if (!reportMarkdown) throw new Error('report_markdown is missing');

const headerText = `📊 *P2P Procurement Report*\n\n👤 *To:* ${adminName}\n🏢 *Team:* ${teamName}\n📁 *Subteam:* ${subteamName}\n✉️ *Submitted by:* ${senderName}\n\nA new procurement analysis report has been generated for your review.`;

// Telegram limit is 4096 chars — truncate with a note if longer
const MAX = 4000;
const reportText = reportMarkdown.length > MAX
  ? reportMarkdown.substring(0, MAX) + '\n\n_[Report truncated — view full report in the dashboard]_'
  : reportMarkdown;

return [{ json: { chat_id: chatId, header_text: headerText, report_text: reportText } }];
